import React from "react";

function Dashboard() {
  const cards = [
    {
      title: "Registered Drain Nodes",
      value: "1,284",
      description: "Active field sensors reporting to the central system"
    },
    {
      title: "Priority Alerts Today",
      value: "37",
      description: "Escalated service alerts requiring official response"
    },
    {
      title: "Monitoring Reliability",
      value: "96.4%",
      description: "Validated data confidence across monitored zones"
    }
  ];

  return (
    <section className="stats-section">
      <div className="container">
        <div className="stats-grid">
          {cards.map((card) => (
            <article className="stat-card" key={card.title}>
              <h3>{card.title}</h3>
              <p className="stat-value">{card.value}</p>
              <p className="stat-description">{card.description}</p>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Dashboard;
